542→): Promise<ObservationRecord[]> {
543→  const workspaceRecord = new RecordId("workspace", workspaceId);
544→
545→  if (sourceAgent) {
546→    const rows = (await surreal.query(
547→      `SELECT * FROM observation WHERE workspace = $ws AND source_agent = $agent ORDER BY created_at DESC;`,
548→      { ws: workspaceRecord, agent: sourceAgent },
549→    )) as Array<ObservationRecord[]>;
550→    return rows[0] ?? [];
551→  }
552→
553→  const rows = (await surreal.query(
554→    `SELECT * FROM observation WHERE workspace = $ws ORDER BY created_at DESC;`,
555→    { ws: workspaceRecord },
556→  )) as Array<ObservationRecord[]>;
557→  return rows[0] ?? [];
