332→/**
333→ * Obtain an OAuth2 JWT access token for MCP endpoints.
334→ * Requires a SurrealDB connection to skip consent screen.
335→ */
336→export async function getOAuthToken(
337→  baseUrl: string,
338→  surreal: Surreal,
339→  sessionHeaders: Record<string, string>,
340→  scopes: string = "graph:read graph:reason session:write offline_access",
341→): Promise<string> {
342→  // Trigger JWKS key generation if not yet done
343→  await fetch(`${baseUrl}/api/auth/jwks`);
344→
345→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
346→    method: "POST",
347→    headers: { "Content-Type": "application/json" },
348→    body: JSON.stringify({
349→      client_name: `test-client-${Date.now()}`,
350→      redirect_uris: ["http://127.0.0.1:9999/callback"],
351→      grant_types: ["authorization_code", "refresh_token"],
352→      response_types: ["code"],
353→      token_endpoint_auth_method: "none",
354→    }),
355→  });
356→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
357→
358→  const { client_id } = (await dcrRes.json()) as { client_id: string };
359→
360→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
361→    cid: client_id,
362→  });
363→
364→  const { verifier, challenge } = generatePkce();
365→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
366→  authUrl.searchParams.set("client_id", client_id);
367→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
368→  authUrl.searchParams.set("response_type", "code");
369→  authUrl.searchParams.set("scope", scopes);
370→  authUrl.searchParams.set("state", "test-state");
371→  authUrl.searchParams.set("code_challenge", challenge);
372→  authUrl.searchParams.set("code_challenge_method", "S256");
373→  authUrl.searchParams.set("resource", baseUrl);
374→
375→  const authRes = await fetch(authUrl.toString(), {
376→    headers: sessionHeaders,
377→    redirect: "manual",
378→  });
379→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
380→
381→  const location = authRes.headers.get("location")!;
382→  const redirectUrl = new URL(location, baseUrl);
383→  const code = redirectUrl.searchParams.get("code") ?? "";
384→  if (!code) throw new Error(`No code in redirect: ${location}`);
385→
386→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
387→    method: "POST",
388→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
389→    body: new URLSearchParams({
390→      grant_type: "authorization_code",
391→      code,
392→      redirect_uri: "http://127.0.0.1:9999/callback",
393→      client_id,
394→      code_verifier: verifier,
395→      resource: baseUrl,
396→    }),
397→  });
398→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
399→
400→  const tokens = (await tokenRes.json()) as { access_token: string };
401→  return tokens.access_token;
402→}
