422→/**
423→ * Create a test user with DPoP-bound token for MCP endpoints.
424→ * Generates key pair, creates identity, seeds broad-access intent, acquires token.
425→ */
426→export async function createTestUserWithMcp(
427→  baseUrl: string,
428→  surreal: Surreal,
429→  suffix: string,
430→  options?: { workspaceId?: string },
431→): Promise<TestUserWithMcp> {
432→  const user = await createTestUser(baseUrl, suffix);
433→
434→  // Generate DPoP key pair
435→  const keyPair = await generateDPoPKeyPair();
436→
437→  // Use provided workspace or create a new one for this test identity
438→  const workspaceId = options?.workspaceId ?? `test-workspace-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
439→  const workspaceRecord = new RecordId("workspace", workspaceId);
440→  if (!options?.workspaceId) {
441→    await surreal.query(`CREATE $workspace CONTENT $content;`, {
442→      workspace: workspaceRecord,
443→      content: {
444→        name: `Test Workspace ${suffix}`,
445→        status: "active",
446→        onboarding_complete: true,
447→        onboarding_turn_count: 0,
448→        onboarding_summary_pending: false,
449→        onboarding_started_at: new Date(),
450→        created_at: new Date(),
451→      },
452→    });
453→  }
454→
455→  // Create identity record for this user
456→  const identityId = `test-identity-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
457→  const identityRecord = new RecordId("identity", identityId);
458→
459→  await surreal.query(`CREATE $identity CONTENT $content;`, {
460→    identity: identityRecord,
461→    content: {
462→      name: `Test User ${suffix}`,
463→      type: "agent",
464→      workspace: workspaceRecord,
465→      identity_status: "active",
466→      created_at: new Date(),
467→    },
468→  });
469→
470→  // Create member_of edge linking identity to workspace (required by DPoP middleware workspace lookup)
471→  await surreal.query(`RELATE $identity->member_of->$workspace SET added_at = time::now();`, {
472→    identity: identityRecord,
473→    workspace: workspaceRecord,
474→  });
475→
476→  // Seed a broad-access authorized intent covering all MCP operations
477→  const broadActions = [
478→    { type: "brain_action", action: "read", resource: "workspace" },
479→    { type: "brain_action", action: "read", resource: "project" },
480→    { type: "brain_action", action: "read", resource: "task" },
481→    { type: "brain_action", action: "read", resource: "decision" },
482→    { type: "brain_action", action: "read", resource: "constraint" },
483→    { type: "brain_action", action: "read", resource: "change_log" },
484→    { type: "brain_action", action: "read", resource: "entity" },
485→    { type: "brain_action", action: "read", resource: "suggestion" },
486→    { type: "brain_action", action: "read", resource: "intent" },
487→    { type: "brain_action", action: "reason", resource: "decision" },
488→    { type: "brain_action", action: "reason", resource: "constraint" },
489→    { type: "brain_action", action: "reason", resource: "commit" },
490→    { type: "brain_action", action: "create", resource: "decision" },
491→    { type: "brain_action", action: "create", resource: "question" },
492→    { type: "brain_action", action: "create", resource: "task" },
493→    { type: "brain_action", action: "create", resource: "note" },
494→    { type: "brain_action", action: "create", resource: "observation" },
495→    { type: "brain_action", action: "create", resource: "suggestion" },
496→    { type: "brain_action", action: "create", resource: "session" },
497→    { type: "brain_action", action: "create", resource: "commit" },
498→    { type: "brain_action", action: "create", resource: "intent" },
499→    { type: "brain_action", action: "update", resource: "task" },
500→    { type: "brain_action", action: "update", resource: "session" },
501→    { type: "brain_action", action: "update", resource: "suggestion" },
502→    { type: "brain_action", action: "submit", resource: "intent" },
503→  ];
504→
505→  const intentId = `test-intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
506→  const intentRecord = new RecordId("intent", intentId);
507→  const traceRecord = new RecordId("trace", `trace-${intentId}`);
508→
509→  await surreal.query(`CREATE $trace CONTENT $traceContent;`, {
510→    trace: traceRecord,
511→    traceContent: { type: "intent_submission", actor: identityRecord, workspace: workspaceRecord, created_at: new Date() },
512→  });
513→
514→  await surreal.query(`CREATE $intent CONTENT $content;`, {
515→    intent: intentRecord,
516→    content: {
517→      goal: "Broad test access",
518→      reasoning: "Pre-authorized for acceptance testing",
519→      status: "authorized",
520→      priority: 50,
521→      authorization_details: broadActions,
522→      dpop_jwk_thumbprint: keyPair.thumbprint,
523→      action_spec: { provider: "test", action: "broad_access", params: {} },
524→      trace_id: traceRecord,
525→      requester: identityRecord,
526→      workspace: workspaceRecord,
527→      evaluation: {
528→        decision: "APPROVE",
529→        risk_score: 0,
530→        reason: "Pre-authorized for testing",
531→        evaluated_at: new Date(),
532→        policy_only: true,
533→      },
534→      created_at: new Date(),
535→    },
536→  });
537→
538→  // Request DPoP-bound access token from Custom AS
539→  const tokenUri = `${baseUrl}/api/auth/token`;
540→  const dpopProof = await createDPoPProof(keyPair, "POST", tokenUri);
541→
542→  const tokenRes = await fetch(tokenUri, {
543→    method: "POST",
544→    headers: {
545→      "Content-Type": "application/json",
546→      DPoP: dpopProof,
547→    },
548→    body: JSON.stringify({
549→      grant_type: "urn:brain:intent-authorization",
550→      intent_id: intentId,
551→      authorization_details: broadActions,
552→    }),
553→  });
554→
555→  if (!tokenRes.ok) {
556→    const body = await tokenRes.text();
557→    throw new Error(`DPoP token acquisition failed (${tokenRes.status}): ${body}`);
558→  }
559→
560→  const { access_token } = (await tokenRes.json()) as { access_token: string };
561→
562→  const mcpFetch = async (path: string, options?: { method?: string; body?: unknown }): Promise<Response> => {
563→    const method = options?.method ?? "POST";
564→    const requestUri = `${baseUrl}${path}`;
565→    const proof = await createDPoPProof(keyPair, method, requestUri);
566→
567→    return fetch(requestUri, {
568→      method,
569→      headers: {
570→        "Content-Type": "application/json",
571→        Authorization: `DPoP ${access_token}`,
572→        DPoP: proof,
573→      },
574→      body: options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({}),
575→    });
576→  };
577→
578→  return {
579→    ...user,
580→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
581→    mcpFetch,
582→    accessToken: access_token,
583→    keyPair,
584→    workspaceId,
585→    identityId,
586→  };
587→}
588→
589→// ---------------------------------------------------------------------------
590→// DPoP Helpers
591→// ---------------------------------------------------------------------------
592→
593→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
594→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
595→    { name: "ECDSA", namedCurve: "P-256" },
596→    true,
597→    ["sign", "verify"],
598→  );
599→
600→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
601→  const thumbprint = await computeDPoPThumbprint(publicJwk);
602→
603→  return { privateKey, publicKey, publicJwk, thumbprint };
604→}
605→
606→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
607→  const thumbprintInput = JSON.stringify({
608→    crv: publicJwk.crv,
609→    kty: publicJwk.kty,
610→    x: publicJwk.x,
611→    y: publicJwk.y,
612→  });
613→
614→  const hashBuffer = await crypto.subtle.digest(
615→    "SHA-256",
616→    new TextEncoder().encode(thumbprintInput),
617→  );
618→
619→  return base64urlBytes(new Uint8Array(hashBuffer));
620→}
621→
622→async function createDPoPProof(
623→  keyPair: DPoPKeyPair,
624→  method: string,
625→  targetUri: string,
626→): Promise<string> {
627→  const header = {
628→    typ: "dpop+jwt" as const,
629→    alg: "ES256" as const,
630→    jwk: {
631→      kty: keyPair.publicJwk.kty,
632→      crv: keyPair.publicJwk.crv,
633→      x: keyPair.publicJwk.x,
634→      y: keyPair.publicJwk.y,
635→    },
636→  };
637→
638→  const payload = {
639→    jti: crypto.randomUUID(),
640→    htm: method,
641→    htu: targetUri,
642→    iat: Math.floor(Date.now() / 1000),
643→  };
644→
645→  const importedKey = await jose.importJWK(
646→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
647→    "ES256",
648→  );
649→
650→  return await new jose.SignJWT(payload)
651→    .setProtectedHeader(header)
652→    .sign(importedKey);
653→}
654→
655→function base64urlBytes(bytes: Uint8Array): string {
656→  const binary = String.fromCharCode(...bytes);
657→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
658→}
659→
660→// ---------------------------------------------------------------------------
661→// Internal Utilities
662→// ---------------------------------------------------------------------------
663→
664→function requireTestEnv(name: string): string {
665→  const value = process.env[name];
666→  if (!value || value.trim().length === 0) {
667→    throw new Error(`Acceptance test requires env var ${name}`);
668→  }
669→  return value;
670→}
671→
672→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
673→  return await Promise.race([
674→    callback(),
675→    new Promise<T>((_, reject) => {
676→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
677→    }),
678→  ]);
679→}
