340→/**
341→ * Creates a learning via the HTTP endpoint (driving port).
342→ */
343→export async function createLearningViaHttp(
344→  baseUrl: string,
345→  user: TestUser,
346→  workspaceId: string,
347→  input: CreateLearningInput,
348→): Promise<Response> {
349→  return fetchRaw(
350→    `${baseUrl}/api/workspaces/${workspaceId}/learnings`,
351→    {
352→      method: "POST",
353→      headers: { "Content-Type": "application/json", ...user.headers },
354→      body: JSON.stringify(input),
355→    },
356→  );
357→}
358→
359→/**
360→ * Lists learnings via the HTTP endpoint (driving port).
361→ */
362→export async function listLearningsViaHttp(
363→  baseUrl: string,
364→  user: TestUser,
365→  workspaceId: string,
366→  params?: { status?: string; type?: string; agent?: string },
367→): Promise<Response> {
368→  const url = new URL(`${baseUrl}/api/workspaces/${workspaceId}/learnings`);
369→  if (params?.status) url.searchParams.set("status", params.status);
370→  if (params?.type) url.searchParams.set("type", params.type);
371→  if (params?.agent) url.searchParams.set("agent", params.agent);
372→
373→  return fetchRaw(url.toString(), {
374→    method: "GET",
375→    headers: user.headers,
376→  });
377→}
378→
379→/**
380→ * Performs a status transition action on a learning via HTTP (driving port).
381→ */
382→export async function performLearningAction(
383→  baseUrl: string,
384→  user: TestUser,
385→  workspaceId: string,
386→  learningId: string,
387→  action: LearningActionInput,
388→): Promise<Response> {
389→  return fetchRaw(
390→    `${baseUrl}/api/workspaces/${workspaceId}/learnings/${learningId}/actions`,
391→    {
392→      method: "POST",
393→      headers: { "Content-Type": "application/json", ...user.headers },
394→      body: JSON.stringify(action),
395→    },
396→  );
397→}
398→
399→/**
400→ * Checks whether evidence edges exist for a learning.
401→ */
402→export async function getLearningEvidence(
403→  surreal: Surreal,
404→  learningId: string,
405→): Promise<Array<{ id: RecordId; out: RecordId }>> {
406→  const learningRecord = new RecordId("learning", learningId);
407→  const rows = (await surreal.query(
408→    `SELECT id, out FROM learning_evidence WHERE in = $learning;`,
409→    { learning: learningRecord },
410→  )) as Array<Array<{ id: RecordId; out: RecordId }>>;
411→  return rows[0] ?? [];
412→}
413→
414→/**
415→ * Checks whether a supersedes edge exists between two learnings.
416→ */
417→export async function getSupersessionEdge(
418→  surreal: Surreal,
419→  newLearningId: string,
420→  oldLearningId: string,
421→): Promise<boolean> {
422→  const newRecord = new RecordId("learning", newLearningId);
423→  const oldRecord = new RecordId("learning", oldLearningId);
424→  const rows = (await surreal.query(
425→    `SELECT id FROM supersedes WHERE in = $new AND out = $old;`,
426→    { new: newRecord, old: oldRecord },
427→  )) as Array<Array<{ id: RecordId }>>;
428→  return (rows[0]?.length ?? 0) > 0;
429→}
430→
431→/**
432→ * Generates a deterministic fake embedding vector for testing.
433→ * NOT for production use -- produces predictable vectors for assertion control.
434→ */
435→export function fakeLearningEmbedding(seed: number, dimension = 1536): number[] {
436→  const embedding: number[] = [];
437→  let value = seed;
438→  for (let i = 0; i < dimension; i++) {
439→    // Simple deterministic pseudo-random based on seed
440→    value = ((value * 1103515245 + 12345) & 0x7fffffff) / 0x7fffffff;
441→    embedding.push(value * 2 - 1); // Range [-1, 1]
442→  }
443→  // Normalize to unit vector
444→  const magnitude = Math.sqrt(embedding.reduce((sum, v) => sum + v * v, 0));
445→  return embedding.map((v) => v / magnitude);
446→}
