export async function getSupersessionEdge(
  surreal: Surreal,
  newLearningId: string,
  oldLearningId: string,
): Promise<boolean> {
  const newRecord = new RecordId("learning", newLearningId);
  const oldRecord = new RecordId("learning", oldLearningId);
  const rows = (await surreal.query(
    `SELECT id FROM supersedes WHERE in = $new AND out = $old;`,
    { new: newRecord, old: oldRecord },
  )) as Array<Array<{ id: RecordId }>>;
  return (rows[0]?.length ?? 0) > 0;
}

/**
 * Generates a deterministic fake embedding vector for testing.
 * NOT for production use -- produces predictable vectors for assertion control.
 */
export function fakeLearningEmbedding(seed: number, dimension = 1536): number[] {
  const embedding: number[] = [];
  let value = seed;
  for (let i = 0; i < dimension; i++) {
    // Simple deterministic pseudo-random based on seed
    value = ((value * 1103515245 + 12345) & 0x7fffffff) / 0x7fffffff;
    embedding.push(value * 2 - 1); // Range [-1, 1]
  }
  // Normalize to unit vector
  const magnitude = Math.sqrt(embedding.reduce((sum, v) => sum + v * v, 0));
  return embedding.map((v) => v / magnitude);
}

